    def validate_cart_items(self, cart_items: List[Dict], user_id: str, user_role: UserRole) -> Dict[str, Any]:
        if not cart_items:
            raise ValueError("Cart is empty")
        
        validated_items = []
        subtotal = 0.0
        
        for item_data in cart_items:
            item = CartItem(
                product_id=item_data["product_id"],
                name=item_data["name"],
                price=item_data["price"],
                quantity=item_data["quantity"],
                category=item_data["category"]
            )
            
            if item.price <= 0 or item.quantity <= 0:
                raise ValueError(f"Invalid price or quantity for item {item.product_id}")
            
            validated_items.append(item)
            subtotal += item.price * item.quantity
        
        self.cart_items = validated_items
        self.user_id = user_id
        self.user_role = user_role
        
        return {
            "status": "validated",
            "items": validated_items,
            "subtotal": round(subtotal, 2),
            "user_id": user_id,
            "user_role": user_role.name
        }
    
    def apply_discount_code(self, code: str) -> Dict[str, Any]:
        if not self.cart_items:
            raise ValueError("Cart items must be validated first")
        
        if code not in self.discount_codes:
            raise ValueError("Invalid discount code")
        
        discount = self.discount_codes[code]
        
        # Server-side authorization check
        if discount.is_admin_only and self.user_role != UserRole.ADMIN:
            raise PermissionError("Admin-only discount code")
        
        if self.user_role not in discount.valid_user_roles:
            raise PermissionError("User role not authorized for this discount")
        
        if discount.used_count >= discount.usage_limit:
            raise ValueError("Discount code usage limit exceeded")
        
        # Recompute discount based on server-side data
        applicable_items = [
            item for item in self.cart_items 
            if item.category in discount.valid_for_categories or "all" in discount.valid_for_categories
        ]
        
        if not applicable_items:
            raise ValueError("No items applicable for this discount")
        
        discount_amount = 0.0
        if discount.discount_type == "percentage":
            discount_amount = sum(item.price * item.quantity for item in applicable_items) * (discount.discount_value / 100)
        elif discount.discount_type == "fixed":
            discount_amount = discount.discount_value
        
        # Update usage count
        self.discount_codes[code].used_count += 1
        self.discount_code = code
        
        return {
            "status": "discount_applied",
            "discount_code": code,
            "discount_amount": round(discount_amount, 2),
            "discount_type": discount.discount_type,
            "discount_value": discount.discount_value
        }
    
    def calculate_tax(self, tax_rate: float = 0.08) -> Dict[str, Any]:
        if not self.cart_items:
            raise ValueError("Cart items must be validated first")
        
        if not self.discount_code:
            discount_amount = 0.0
